import React from 'react';
import { createRoot } from 'react-dom/client';
import './styles.css';
import { App } from './App';

createRoot(document.getElementById('root')!).render(
  <React.StrictMode>
    <App />
  </React.StrictMode>,
);

const features: string[] = ['Typed components', 'Fast Vite build', 'Nix project runner'];

export function App() {
  return (
    <main>
      <section>
        <p className="eyebrow">Codeleon React</p>
        <h1>Build a typed frontend starter.</h1>
        <ul>
          {features.map((feature) => (
            <li key={feature}>{feature}</li>
          ))}
        </ul>
      </section>
    </main>
  );
}

:root { font-family: Inter, system-ui, sans-serif; color: #f4f4f5; background: #09090b; }
body { margin: 0; }
main { min-height: 100vh; display: grid; place-items: center; padding: 2rem; }
section { width: min(720px, 100%); }
.eyebrow { color: #22d3ee; text-transform: uppercase; letter-spacing: .12em; font-size: .75rem; font-weight: 700; }
h1 { font-size: clamp(2.5rem, 8vw, 5rem); line-height: .95; margin: 0 0 1.5rem; }
ul { display: grid; gap: .75rem; padding: 0; list-style: none; }
li { border: 1px solid #27272a; border-radius: 8px; padding: .85rem 1rem; background: #18181b; }
